SELECT count(*) FROM movie_companies, company_type, title, company_name, movie_keyword, keyword, movie_info WHERE movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND movie_info.movie_id = title.id;